starter:
function reverseRange(a, i, j) {
  // your code here
}

solution:
function reverseRange(a, i, j) {
  let lo = i, hi = j;
  while (lo < hi) {
    const tmp = a[lo];
    a[lo] = a[hi];
    a[hi] = tmp;
    lo++;
    hi--;
  }
  return a;
}

tests:
if (JSON.stringify(reverseRange([1, 2, 3, 4, 5], 1, 3)) !== JSON.stringify([1, 4, 3, 2, 5])) throw new Error('mid');
if (JSON.stringify(reverseRange([1, 2, 3, 4], 0, 3)) !== JSON.stringify([4, 3, 2, 1])) throw new Error('whole');
if (JSON.stringify(reverseRange([1, 2, 3], 1, 1)) !== JSON.stringify([1, 2, 3])) throw new Error('single');
const a = [7, 8, 9];
reverseRange(a, 0, 2);
if (JSON.stringify(a) !== JSON.stringify([9, 8, 7])) throw new Error('in place');

solution:
function isPalindrome(a) {
  let lo = 0, hi = a.length - 1;
  while (lo < hi) {
    if (a[lo] !== a[hi]) return false;
    lo++;
    hi--;
  }
  return true;
}

tests:
if (isPalindrome([1, 2, 3, 2, 1]) !== true) throw new Error('odd');
if (isPalindrome([1, 2, 2, 1]) !== true) throw new Error('even');
if (isPalindrome([1, 2, 3]) !== false) throw new Error('no');
if (isPalindrome([]) !== true) throw new Error('empty');
if (isPalindrome([9]) !== true) throw new Error('single');

