starter:
function maxWindowSum(a, k) {
  // your code here
}

solution:
function maxWindowSum(a, k) {
  let sum = 0;
  for (let t = 0; t < k; t++) sum += a[t];
  let best = sum;
  for (let i = k; i < a.length; i++) {
    sum += a[i] - a[i - k];
    if (sum > best) best = sum;
  }
  return best;
}

tests:
if (maxWindowSum([1, 2, 3, 4, 5], 2) !== 9) throw new Error('9');
if (maxWindowSum([2, 1, 5, 1, 3, 2], 3) !== 9) throw new Error('9b');
if (maxWindowSum([4], 1) !== 4) throw new Error('single');
if (maxWindowSum([-1, -2, -3], 2) !== -3) throw new Error('neg');

