solution:
function binarySearch(a, target) {
  let lo = 0, hi = a.length - 1;
  while (lo <= hi) {
    const mid = Math.floor((lo + hi) / 2);
    if (a[mid] === target) return mid;
    if (a[mid] < target) lo = mid + 1;
    else hi = mid - 1;
  }
  return -1;
}

tests:
if (binarySearch([1, 3, 5, 7, 9], 7) !== 3) throw new Error('found');
if (binarySearch([1, 3, 5, 7, 9], 1) !== 0) throw new Error('first');
if (binarySearch([1, 3, 5, 7, 9], 9) !== 4) throw new Error('last');
if (binarySearch([1, 3, 5, 7, 9], 4) !== -1) throw new Error('absent');
if (binarySearch([], 3) !== -1) throw new Error('empty');
if (binarySearch([5], 5) !== 0) throw new Error('single');
